const { APP_FILE_MEMBERS } = require('../../../constants/file');
const { IMPORT_TYPES } = require('../../../constants/islands');
const { NordicIslandsError } = require('../../../error/nordic-islands-error');
const { getPotentialReactComponentNodes } = require('./react-component-nodes');
const { getSortedJSXElementsFromAST } = require('./elements-of-ast');
const {
  getSortingComponentsError,
} = require('../../../error/get-discovery-error');

/**
 * @param {{ importName: string, namedExport: boolean, property: string? }} component
 * @param {Record<string, import('./react-component-nodes').ComponentNode | undefined>} nodes
 * @param {import('../../../cache/ast-cache').BabelAST} originalAst
 */
const getAstByComponentData = (
  { importName, namedExport, property },
  reactComponentNodes,
  originalAst,
) => {
  const astNodeName = namedExport
    ? importName
    : Object.keys(reactComponentNodes).find(
        (name) =>
          typeof reactComponentNodes[name]?.namedExport === 'boolean' &&
          !reactComponentNodes[name].namedExport,
      );

  if (!astNodeName) {
    return [originalAst];
  }

  const astNodeNames = property
    ? Object.keys(reactComponentNodes).filter((name) =>
        name.startsWith(`${astNodeName}-`),
      )
    : [astNodeName];

  const asts = [];

  astNodeNames.forEach((nodeName) => {
    if (reactComponentNodes[nodeName]?.node) {
      asts.push(...Array.from(reactComponentNodes[nodeName].node));
      delete reactComponentNodes[nodeName];
    }
  });

  return asts;
};

/**
 * @param {import('../../../cache/ast-cache').BabelAST} ast
 * @param {string} filePath
 * @param {{ importedComponents: import('../../../helpers/islands/component').ComponentManifest, islandWrapper: string | null }} componentsUsedInFile
 * @param {{ importName: string, namedExport: boolean, property: string? }} [component]
 * @returns {import('./elements-of-ast').JSXElementsManifest | {}}
 */
const getSortedJSXElementsOfComponent = (
  ast,
  filePath,
  { importedComponents, islandWrapper },
  { importName, namedExport, property } = {
    importName: IMPORT_TYPES.DEFAULT,
    namedExport: false,
  },
) => {
  try {
    const sortedElements = {};
    const reactComponentNodes = getPotentialReactComponentNodes(ast, filePath);

    const astsToAnalize = getAstByComponentData(
      { importName, namedExport, property },
      reactComponentNodes,
      ast,
    );

    if (!astsToAnalize.length) {
      return sortedElements;
    }

    astsToAnalize.forEach((astToAnalize) => {
      Object.assign(
        sortedElements,
        getSortedJSXElementsFromAST(astToAnalize, {
          filePath,
          nodes: reactComponentNodes,
          importedComponents,
          islandWrapper,
        }),
      );
    });

    return sortedElements;
  } catch (error) {
    throw new NordicIslandsError(
      getSortingComponentsError(error.message),
      {
        type: `${APP_FILE_MEMBERS.PAGE} or ${APP_FILE_MEMBERS.COMPONENT}`,
        path: filePath,
      },
      error,
    );
  }
};

module.exports = {
  getSortedJSXElementsOfComponent,
};
